const MAIN_WEBHOOK      = 'https://intranet.rajlaxmiworld.com/rest/316/du14lqdt4ijmvzx4';
const ACTIVITY_WEBHOOK  = 'https://intranet.rajlaxmiworld.com/rest/71603/jqz6l15bjdnyx803';
const BITRIX_DOMAIN     = 'https://intranet.rajlaxmiworld.com';
const HOD_NAME          = 'Dr. Aarti Arya';
const HOD_EMAIL         = 'dr.aartiarya@rajlaxmiworld.com';
const TARGET_DEPARTMENT = 'Bitrix24 Team';
const CC_EMAIL = 'bhagwati@rajlaxmiworld.com';
const SENDER_NAME       = 'Averlon System';

const IST_OFFSET_MS = 5.5 * 60 * 60 * 1000;
const nowIST        = new Date(Date.now() + IST_OFFSET_MS);
const todayStr      = nowIST.toISOString().slice(0, 10);

function parseDateStr(str) {
  const [y, m, d] = str.split('-').map(Number);
  return new Date(y, m - 1, d);
}
function parseBitrixDate(dateStr) {
  if (!dateStr) return null;
  const part = new Date(dateStr).toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  return parseDateStr(part);
}
function formatDate(dateStr) {
  const d = parseBitrixDate(dateStr);
  if (!d) return '\u2014';
  return d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
}

const today          = parseDateStr(todayStr);
const windowStart    = new Date(today); windowStart.setDate(windowStart.getDate() - 30);
const windowStartStr = windowStart.toISOString().slice(0, 10);
const yesterdayStr   = new Date(today.getTime() - 86400000).toISOString().slice(0, 10);

const deptRes = await this.helpers.request({ method: 'GET', url: `${MAIN_WEBHOOK}/department.get.json`, json: true });
const deptMap = {};
for (const d of (deptRes.result || [])) deptMap[String(d.ID)] = d.NAME || '';
const targetDeptIds = Object.entries(deptMap)
  .filter(([, name]) => name.toLowerCase().includes(TARGET_DEPARTMENT.toLowerCase()))
  .map(([id]) => id);
if (targetDeptIds.length === 0) throw new Error(`Dept "${TARGET_DEPARTMENT}" not found`);

let allUsers = [], uStart = 0, uMore = true;
while (uMore) {
  const res = await this.helpers.request({ method: 'GET', url: `${MAIN_WEBHOOK}/user.get.json?filter[ACTIVE]=true&start=${uStart}`, json: true });
  allUsers = allUsers.concat(res.result || []);
  uMore = !!(res.next && (res.result || []).length > 0);
  if (uMore) uStart = res.next;
}
const userMap = {};
for (const u of allUsers) {
  const uid = String(u.ID);
  const userDeptIds = Array.isArray(u.UF_DEPARTMENT) ? u.UF_DEPARTMENT.map(String) : (u.UF_DEPARTMENT ? [String(u.UF_DEPARTMENT)] : []);
  if (!userDeptIds.some(d => targetDeptIds.includes(d))) continue;
  let email = Array.isArray(u.EMAIL) ? (u.EMAIL[0]?.VALUE || '') : (u.EMAIL || '');
  userMap[uid] = { id: uid, name: `${u.NAME || ''} ${u.LAST_NAME || ''}`.trim(), email: email.trim() };
}

let allDeals = [], dStart = 0, dMore = true;
while (dMore) {
  const res = await this.helpers.request({
    method: 'GET',
    url: `${ACTIVITY_WEBHOOK}/crm.deal.list.json?filter[CLOSED]=N&select[]=ID&select[]=TITLE&select[]=OPPORTUNITY&select[]=CURRENCY_ID&start=${dStart}`,
    json: true
  });
  allDeals = allDeals.concat(res.result || []);
  dMore = !!(res.next && (res.result || []).length > 0);
  if (dMore) dStart = res.next;
}
const dealMap = {};
for (const d of allDeals) dealMap[String(d.ID)] = d;

const grouped = {};
for (const uid of Object.keys(userMap)) {
  let aStart = 0, aMore = true;
  while (aMore) {
    const res = await this.helpers.request({
      method: 'GET',
      url: `${ACTIVITY_WEBHOOK}/crm.activity.list.json` +
           `?filter[RESPONSIBLE_ID]=${uid}` +
           `&filter[COMPLETED]=N` +
           `&filter[>=DEADLINE]=${windowStartStr}` +
           `&filter[<=DEADLINE]=${yesterdayStr}` +
           `&select[]=ID&select[]=SUBJECT&select[]=DEADLINE&select[]=RESPONSIBLE_ID` +
           `&select[]=TYPE_ID&select[]=OWNER_ID&select[]=OWNER_TYPE_ID` +
           `&start=${aStart}`,
      json: true
    });
    const batch = res.result || [];
    for (const act of batch) {
      const d = parseBitrixDate(act.DEADLINE);
      if (!d || d >= today) continue;
      const ownerTypeId = String(act.OWNER_TYPE_ID || '');
      const ownerId     = String(act.OWNER_ID || '');
      const deal        = ownerTypeId === '2' ? dealMap[ownerId] : null;
      const daysOv      = Math.floor((today - d) / 86400000);
      if (!grouped[uid]) grouped[uid] = { employee: userMap[uid], deals: [] };
      grouped[uid].deals.push({
        title:       deal ? (deal.TITLE || `Deal #${ownerId}`) : (act.SUBJECT || 'No Subject'),
        dueDate:     formatDate(act.DEADLINE),
        amount:      deal ? `${deal.OPPORTUNITY || 0} ${deal.CURRENCY_ID || ''}`.trim() : '\u2014',
        status:      `Overdue by ${daysOv} day(s)`,
        daysOverdue: daysOv,
        url:         ownerTypeId === '2' ? `${BITRIX_DOMAIN}/crm/deal/details/${ownerId}/` : `${BITRIX_DOMAIN}/crm/`
      });
    }
    aMore = !!(res.next && batch.length > 0);
    if (aMore) aStart = res.next;
  }
}

const employeeGroups = Object.values(grouped).filter(e => e.deals.length > 0);

return [{
  json: {
    hodName:        HOD_NAME,
    hodEmail:       HOD_EMAIL,
     ccEmail:        CC_EMAIL, 
    senderName:     SENDER_NAME,
    runDate:        todayStr,
    hasDeals:       employeeGroups.length > 0,
    employeeGroups,
    totalEmployees: employeeGroups.length,
    totalDeals:     employeeGroups.reduce((s, e) => s + e.deals.length, 0)
  }
}];

const data = $json;
const { employeeGroups, hodName, runDate, totalEmployees, totalDeals, senderName , ccEmail } = data;

function esc(str = '') {
  return String(str).replace(/[&<>"']/g, s => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[s]));
}

const blocks = employeeGroups.map(({ employee, deals }) => {
  const rows = deals.map(d => `<tr style="border-bottom:1px solid #f0ede6;"><td style="padding:10px 8px;font-size:13px;color:#2c2c2a;">${esc(d.title)}</td><td style="padding:10px 8px;font-size:13px;color:#5f5e5a;white-space:nowrap;">${esc(d.dueDate)}</td><td style="padding:10px 8px;font-size:13px;color:#5f5e5a;">${esc(d.amount)}</td><td style="padding:10px 8px;font-size:12px;color:#A32D2D;font-weight:600;">${esc(d.status)}</td></tr>`).join('');
  return `<div style="margin-bottom:24px;border:1px solid #e0ddd6;border-radius:10px;overflow:hidden;"><div style="background:#f7f5f0;padding:12px 20px;border-bottom:1px solid #e0ddd6;"><span style="font-size:15px;font-weight:600;color:#2c2c2a;">${esc(employee.name)}</span><span style="font-size:12px;color:#888780;margin-left:10px;">${deals.length} overdue deal(s)</span></div><table style="width:100%;border-collapse:collapse;"><thead><tr style="background:#faf9f6;"><th style="padding:9px 8px;text-align:left;font-size:11px;color:#888780;font-weight:600;">DEAL NAME</th><th style="padding:9px 8px;text-align:left;font-size:11px;color:#888780;font-weight:600;">DUE DATE</th><th style="padding:9px 8px;text-align:left;font-size:11px;color:#888780;font-weight:600;">AMOUNT</th><th style="padding:9px 8px;text-align:left;font-size:11px;color:#888780;font-weight:600;">STATUS</th></tr></thead><tbody>${rows}</tbody></table></div>`;
}).join('');

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;background:#f4f4f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;"><div style="max-width:680px;margin:32px auto;background:white;border-radius:12px;overflow:hidden;border:1px solid #d3d1c7;"><div style="background:#1a3a2a;padding:28px 32px;"><div style="font-size:11px;color:#ffffff;opacity:0.8;font-weight:600;letter-spacing:1px;text-transform:uppercase;margin-bottom:6px;">${esc(senderName)}</div><h1 style="margin:0;color:white;font-size:22px;font-weight:600;">Morning Overdue Summary</h1><div style="color:#ffffff;opacity:0.85;font-size:13px;margin-top:6px;">11:00 AM - ${runDate} - Deals overdue till yesterday</div></div><div style="padding:24px 32px;"><p style="font-size:15px;color:#2c2c2a;margin:0 0 6px;">Hi <strong>${esc(hodName)}</strong>,</p><p style="font-size:14px;color:#5f5e5a;margin:0 0 24px;">Here is your morning summary. <strong>${totalEmployees} employee(s)</strong> have a total of <strong>${totalDeals} overdue deal(s)</strong> pending from yesterday or earlier.</p>${blocks}</div><div style="padding:16px 32px;border-top:1px solid #e8e8e8;"><p style="font-size:12px;color:#888780;margin:0;">Automated morning report from ${esc(senderName)}. Do not reply.</p></div></div></body></html>`;

return [{ json: { ...data, emailHtml: html, emailSubject: `[ Morning Summary Bitrix24 Team ] ${totalDeals} Overdue Deal(s) Across ${totalEmployees} Employee(s) - ${runDate}`, ccEmail: ccEmail } }];

const { hodName, runDate, senderName, hodEmail } = $json;
const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;background:#f4f4f0;font-family:sans-serif;"><div style="max-width:600px;margin:32px auto;background:white;border-radius:12px;padding:32px;border:1px solid #d3d1c7;text-align:center;"><div style="font-size:48px;margin-bottom:16px;">&#10003;</div><h2 style="color:#1a3a2a;margin:0 0 12px;">All Clear!</h2><p style="color:#5f5e5a;">Hi ${hodName}, no overdue deals from yesterday or earlier as of ${runDate}.</p><p style="font-size:12px;color:#888780;margin-top:24px;">Automated morning report from ${senderName}. Do not reply.</p></div></body></html>`;
return [{ json: { hodName, hodEmail, senderName, runDate, emailHtml: html, emailSubject: `[Morning Summary] No Overdue Deals - ${runDate}` } }];

const payload = $json;

const tokenRes = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://login.microsoftonline.com/f284e063-bc3b-44ac-b38c-418c4012e4e8/oauth2/v2.0/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: 'grant_type=client_credentials&client_id=e5c42145-d918-4fb3-989d-bcc2093e5a42&client_secret=0xm8Q~WQHXtDZBy2Aitz6U.7Hgm9BRkst2MJOdhr&scope=https%3A%2F%2Fgraph.microsoft.com%2F.default',
});

const token = typeof tokenRes === 'string' ? JSON.parse(tokenRes) : tokenRes;

return {
  json: {
    hodName:      payload.hodName,
    hodEmail:     payload.hodEmail,
     ccEmail:      payload.ccEmail, 
    senderName:   payload.senderName,
    runDate:      payload.runDate,
    emailHtml:    payload.emailHtml,
    emailSubject: payload.emailSubject,
    access_token: token.access_token
  }
};
